mapper.select:
select d.id, d.name, d.category_id as categoryId, d.price, d.image, d.description, d.status, d.create_time as createTime, d.update_time as updateTime, c.name as categoryName from dish d left join category c on d.category_id = c.id
and d.name like concat('%', #{name}, '%')
and d.category_id = #{categoryId}
and d.status = #{status}
order by d.update_time desc
